import{_ as t,o as e,c as r,ai as a}from"./chunks/framework.CKB5fCPB.js";const h=JSON.parse('{"title":"Port forwarding","description":"","frontmatter":{},"headers":[],"relativePath":"network/Port forwarding.md","filePath":"network/Port forwarding.md"}'),i={name:"network/Port forwarding.md"};function n(s,o,d,l,c,u){return e(),r("div",null,[...o[0]||(o[0]=[a('<h1 id="port-forwarding" tabindex="-1">Port forwarding <a class="header-anchor" href="#port-forwarding" aria-label="Permalink to “Port forwarding”">​</a></h1><p>A common issue is that ports arent being forwarded which will lead to connection failures. Since there are so many different setups its hard to make a guide on how to do it.</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>You can use tools like <a href="https://canyouseeme.org/" target="_blank" rel="noreferrer">https://canyouseeme.org/</a> to check if your port is publicly available. If not, your port is not forwarded.</p></div><p>In addition to port forwarding its also possible that a firewall is blocking the forwarded port as well. This could be done on an OS level or in your router, or maybe both. Since this depends on many factors its again hard to make a guide about it, which is why its recommended to check google for your specific setup.</p><hr><h2 id="log-into-router" tabindex="-1">Log into router <a class="header-anchor" href="#log-into-router" aria-label="Permalink to “Log into router”">​</a></h2><p>Usually on the back or somewhere on your (wifi) router you should be able to find a sticker with infos about a dashboard or login infos and an address. You can enter that address in your browser and use the login information to get access to the admin panel.</p><p>From that point on you will need to do a bit of research on how to forward ports on your specific model. Generally it can be found in settings like &quot;Network Settings&quot; or &quot;Security&quot;. With a bit of exploring you might find it yourself.</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Depending on your router you may need to enable something similar to an &quot;advanced mode&quot;.</p></div>',9)])])}const f=t(i,[["render",n]]);export{h as __pageData,f as default};
